     1→import { useState, useEffect, useCallback } from "react";
     2→import { LANGUAGES } from "../languages";
     3→
     4→export function useLocalization() {
     5→  const getInitialLanguage = useCallback(() => {
     6→    const savedLanguageId = localStorage.getItem("lang");
     7→    return (
     8→      LANGUAGES.find((lang) => lang.id === savedLanguageId) || LANGUAGES[0]
     9→    );
    10→  }, []);
    11→
    12→  const [currentLanguage, setCurrentLanguage] = useState(getInitialLanguage);
    13→
    14→  useEffect(() => {
    15→    localStorage.setItem("lang", currentLanguage.id);
    16→  }, [currentLanguage]);
    17→
    18→  const setLanguage = (languageId: string) => {
    19→    const newLanguage = LANGUAGES.find((lang) => lang.id === languageId);
    20→    if (newLanguage) {
    21→      setCurrentLanguage(newLanguage);
    22→      window.location.reload();
    23→    } else {
    24→      console.warn(`Language not found: ${languageId}`);
    25→    }
    26→  };
    27→
    28→  return {
    29→    currentLanguage,
    30→    setLanguage,
    31→  };
    32→}
    33→

